module top_module(
    input [3:0] in,
    output reg count
);reg [2:0] i;
    reg [3:0] current_bit;
    reg [2:0] zeroes_count;

    always @* begin
        zeroes_count = 0;
        for (i = 0; i < 4; i = i + 1) begin
            current_bit = in[i];
            if (current_bit == 1) begin
                zeroes_count = zeroes_count + 1;
            end
        end
        count = zeroes_count;
    end

endmodule
